<?php if ( ! defined( 'ABSPATH' ) ) exit; global $wpdb; ?>
<div class="wrap qm2026"><h1><?php esc_html_e('Participantes',QM2026_TEXT_DOMAIN); ?></h1><table class="widefat striped"><thead><tr><th><?php esc_html_e('Nombre',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Email',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Quiniela',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Registro',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Puntos',QM2026_TEXT_DOMAIN); ?></th><th><?php esc_html_e('Link privado',QM2026_TEXT_DOMAIN); ?></th></tr></thead><tbody><?php foreach($wpdb->get_results('SELECT p.*,pool.name pool_name,COALESCE(SUM(s.points),0) pts FROM '.qm2026_table('participants').' p LEFT JOIN '.qm2026_table('pools').' pool ON pool.id=p.pool_id LEFT JOIN '.qm2026_table('scores').' s ON s.participant_id=p.id GROUP BY p.id ORDER BY p.created_at DESC') as $p): $url=add_query_arg('qm2026_token',$p->token,home_url('/')); ?><tr><td><?php echo esc_html($p->name); ?></td><td><?php echo esc_html($p->email); ?></td><td><?php echo esc_html($p->pool_name); ?></td><td><?php echo esc_html($p->created_at); ?></td><td><?php echo esc_html($p->pts); ?></td><td><code><?php echo esc_html($url); ?></code></td></tr><?php endforeach; ?></tbody></table></div>
